    async def export_cdrs(
        self,
        auth_id: str,
        *,
        from_number: typing.Optional[str] = None,
        to_number: typing.Optional[str] = None,
        start_date: typing.Optional[dt.date] = None,
        end_date: typing.Optional[dt.date] = None,
        call_direction: typing.Optional[ExportCdrsRequestCallDirection] = None,
        min_duration: typing.Optional[int] = None,
        sip_call_id: typing.Optional[str] = None,
        bridge_uuid: typing.Optional[str] = None,
        hangup_cause: typing.Optional[str] = None,
        hangup_disposition: typing.Optional[str] = None,
        context: typing.Optional[str] = None,
        campaign_id: typing.Optional[str] = None,
        search: typing.Optional[str] = None,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> typing.AsyncIterator[bytes]:
        """
        Returns CDR data as a downloadable CSV file. Same filters as the list endpoint.

        **Note:** Do NOT send `Accept: application/json` on this endpoint - the response is `text/csv`.

        Parameters
        ----------
        auth_id : str
            Your account Auth ID

        from_number : typing.Optional[str]
            Filter by the originating phone number (caller).

        to_number : typing.Optional[str]
            Filter by the destination phone number (callee).

        start_date : typing.Optional[dt.date]
            Beginning of the search period (YYYY-MM-DD). Required when using `end_date`.

        end_date : typing.Optional[dt.date]
            End of the search period (YYYY-MM-DD). Required when using `start_date`.

        call_direction : typing.Optional[ExportCdrsRequestCallDirection]
            Filter by direction.

        min_duration : typing.Optional[int]
            Minimum call duration in seconds. Excludes calls shorter than this value.

        sip_call_id : typing.Optional[str]
            Filter by the SIP Call-ID of the call (matches the cdr's sip_call_id field).

        bridge_uuid : typing.Optional[str]
            Filter by the UUID of the bridged leg (matches the cdr's bridge_uuid field).

        hangup_cause : typing.Optional[str]
            Filter by telephony hangup cause, e.g. NORMAL_CLEARING.

        hangup_disposition : typing.Optional[str]
            Filter by how the leg was released, e.g. send_refuse.

        context : typing.Optional[str]
            Filter by the call context, e.g. sip-trunking.

        campaign_id : typing.Optional[str]
            Filter by the campaign identifier associated with the call.

        search : typing.Optional[str]
            Free-text search across CDR fields (numbers, IDs, etc.).

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration. You can pass in configuration such as `chunk_size`, and more to customize the request and response.

        Returns
        -------
        typing.AsyncIterator[bytes]
            CSV file containing CDR rows
        """
        async with self._raw_client.export_cdrs(
            auth_id,
            from_number=from_number,
            to_number=to_number,
            start_date=start_date,
            end_date=end_date,
            call_direction=call_direction,
            min_duration=min_duration,
            sip_call_id=sip_call_id,
            bridge_uuid=bridge_uuid,
            hangup_cause=hangup_cause,
            hangup_disposition=hangup_disposition,
            context=context,
            campaign_id=campaign_id,
            search=search,
            request_options=request_options,
        ) as r:
            async for _chunk in r.data:
                yield _chunk

    async def get_cdr(
        self, auth_id: str, call_id: str, *, request_options: typing.Optional[RequestOptions] = None
    ) -> GetCdrResponse:
        """
        Retrieve the CDR for a specific completed call using its `call_id`.
        Useful when you have a `call_id` from a callback or previous API response.

        Parameters
        ----------
        auth_id : str
            Your account Auth ID

        call_id : str
            The unique call ID of the completed call.

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        GetCdrResponse
            CDR details

        Examples
        --------
        import asyncio

        from vobiz import AsyncVobiz

        client = AsyncVobiz(
            auth_token="YOUR_AUTH_TOKEN",
            api_key="YOUR_API_KEY",
        )


        async def main() -> None:
            await client.cdr.get_cdr(
                auth_id="MA_XXXXXX",
                call_id="abc123-def456-ghi789",
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.get_cdr(auth_id, call_id, request_options=request_options)
        return _response.data
